/**
 * data/topics/index.ts
 * Expanded dataset — topics generated programmatically to match the Topic type.
 * Each section has exactly 3 QuickQuestions. Final quiz has 3 separate questions.
 */
import type { Topic, QuickQuestion, TopicSection } from "../../types/topic";

// ─── Helpers ────────────────────────────────────────────────────────────────

function q(
  question: string,
  opts: [string, string, string, string],
  ans: 0 | 1 | 2 | 3,
  hint: string
): QuickQuestion {
  return { q: question, opts, ans, hint };
}

function sec(
  heading: string,
  body: string,
  ...qs: QuickQuestion[]
): TopicSection {
  return { heading, body, questions: qs };
}

