const allTopics: Topic[] = [
  ...literacyTopics,
  ...mathematicsTopics,
  ...englishTopics,
  ...kiswahiliTopics,
  ...environmentalTopics,
  ...hygieneTopics,
  ...religiousTopics,
  ...movementTopics,
];

export const getTopicsBySubject = (subjectId: string): Topic[] =>
  allTopics.filter((t) => t.subjectId === subjectId);

export const getTopicById = (id: string): Topic | undefined =>
  allTopics.find((t) => t.id === id);

export default allTopics;
